var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"악마는 달콤한 말로 사람을 속이고, 타락시키는 사악한 존재… 라고 알려졌지.","JPN":"悪魔は甘い言葉で人を惑わし、堕落させる邪悪な存在……と言われているわね。","ENG":"Devils tempt and corrupt people with their sweet whispers... or so they say.","TWN":"人們對於魔鬼的理解，就是他們會用甜言蜜語欺哄人，企圖使人墮落的邪惡象徵…。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"성황청의 오랜 노력에도 불구하고, 도시엔 여전히 순진한 사람들을 노리는 악마가 숨어 있어.","JPN":"聖皇庁の長きにわたる努力にもかかわらず、\\n都市には依然として純粋な人々を狙う悪魔が潜んでいる。","ENG":"Despite the Holy Curia's long years of efforts, devils still lurk in human cities, preying upon the innocent.","TWN":"聖皇廳雖然長久以來一直持續努力著，但魔鬼依舊藏身在都市裡，覬覦著尚未墮落的人。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"성자의 이름으로 그 악마들을 처단하고 무고한 어린양을 지켜내는 것이 성황청 구마회의 소명.","JPN":"聖者の名のもとにその悪魔たちを祓い、罪のない子羊を守り抜くのが聖皇庁祓魔会の使命。","ENG":"The Holy Curia's Exorcism Council exists to punish devils and protect the innocent in the name of the Son.","TWN":"而聖皇廳驅魔會的使命，就是要以聖者之名趕除魔鬼，拯救無辜的小羊。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 그 도시에 니콜이라는 이름의 퇴마사가 파견된 거야.","JPN":"だから、その都市にニコルという名のエクソシストが派遣されたわけ。","ENG":"That's why they sent this exorcist named Nicole to the city,","TWN":"為此，名叫妮可的驅魔師奉命來到都市。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"\\n도시의 한 술집에 악마가 나타난다는 소문이 돌고 있었거든.","JPN":"\\n都市内のとある酒場に悪魔が現れたという噂が流れていたからね。","ENG":"[[","TWN":"\\n大家都在傳，說魔鬼出現在都市裡的一間酒吧。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"니콜은 그 술집의 바텐더로 일하며 악마의 정체를 캐내는 임무를 맡게 됐어.","JPN":"ニコルはその酒場のバーテンダーとして働きながら、悪魔の正体を暴く任務を任された。","ENG":"Nicole was tasked to work as a bartender there and investigate the devil.","TWN":"妮可於是在偽裝成酒吧裡的調酒師，目的是要揭露魔鬼的真實身分。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"\\n구마 서품을 받은 정식 엑소시스트라고는 하지만… 니콜은 긴장돼서 심장이 두근거렸지.","JPN":"\\n祓魔の命を受けた正式エクソシストとはいえ……\\nニコルは緊張で心臓がドキドキしていたの。","ENG":"[[","TWN":"\\n雖然妮可是有官方授予證明的驅魔師…不過她還是緊張到心臟狂跳。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"혼자서 임무를 맡게 된 것도 처음이지만, 무엇보다 도시라는 곳에 대한 경험이 전혀 없었거든.","JPN":"一人で任務をこなすのも初めてだったけど、\\n何より都会という場所に出た経験がまったくなかったからね。","ENG":"She'd never been on a mission alone, and most of all, she'd never been in a city before.","TWN":"因為這是她第一次獨自執行任務，但更令她緊張的是，這也是她第一次到都市。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 가진 거라곤 그간 수도원에서 읽어온 수많은 책에 대한 기억…","JPN":"彼女が持っていたのは、今まで修道院で読んできた数々の本に書かれた知識……","ENG":"The only things she had were what she'd read from the numerous books in her monastery...","TWN":"陪伴她來到這裡的，只有以前在修道院讀過的書…"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"\\n그리고 다른 형제자매들처럼 잘 해낼 수 있을 거라는 막연한 믿음뿐이었어.","JPN":"\\nそして、他のシスターやブラザーたちのようにうまくできるという漠然とした信念だけだった。","ENG":"[[","TWN":"\\n以及相信她也可以像其他弟兄姊妹一樣，順利完成任務的微小信心。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음… 분명 이쯤에 그 술집이 있어야 하는데요.","JPN":"ええっと……確かこの辺に例の酒場があるはずですが。","ENG":"Mm... That bar should be here somewhere...","TWN":"嗯…怎麼沒看到酒吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"신부님도 참 너무하시죠. 다른 일로 바쁘시다곤 하지만 주소도 안 적힌 가게 명함만 주시다니…","JPN":"神父様もひどいです。他の仕事で忙しいとはいえ、\\n住所すら書かれてないお店の名刺だけ渡すなんて……","ENG":"I can't believe Father did this to me. I understand he was busy, but the business card he gave me doesn't even have an address on it.","TWN":"神父也真是的！就算他很忙，也不能只給我一張上面連地址都沒有的名片吧…"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"게다가 여긴 하나같이 간판도 없고 건물 생김새도 다 비슷해서 어디가 어딘지 모르겠네요.","JPN":"それにこの街はどこも看板が無いし建物も似ているしで、ここがどこだかさっぱりわかりませんね。","ENG":"Also, all the buildings here look similar and have no signboards. I don't know where is where.","TWN":"而且這裡的店家都沒有招牌，建築物長得也都一模一樣，根本搞不清楚哪裡是哪裡嘛！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"비밀임무라고 해서 첨단장비 같은 걸 기대한 건 제 잘못일까요?","JPN":"秘密任務と聞いて､最先端装備を期待していた私がいけないのでしょうか。","ENG":"Maybe it was my fault for expecting cutting-edge equipment for this secret mission.","TWN":"神父說是秘密任務，我還以為會給我什麼很厲害的裝備。只能說沒有期待就沒有傷害，這句話果然是對的嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아니, 장비는커녕 돈도 제대로 못 받아서 오는 내내 초코바만 먹는 신세이고 말이죠.","JPN":"いえ、装備どころか給料もまともにもらえてないせいで、\\nここに来るまでずっとチョコバーばかりの生活を送っているんですし。","ENG":"In reality, I didn't even get enough money to buy anything but energy bars on my way here.","TWN":"不要說是裝備，連旅費都沒給我，害我來的路上只能吃巧克力棒果腹！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아니야.","JPN":"だめです。","ENG":"No.","TWN":"不！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};